4px 8px; 	background: rgba(255, 255, 255, 0.1); 	border-radius: 12px; 	font-size: 12px; 	font-weight: 500; 	opacity: 0; 	transform: scale(0.8); 	transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1); } .slide.active .badge { 	opacity: 1; 	transform: scale(1); } .slide.active .badge:nth-child(1) { 	transition-delay: 0.85s; } .slide.active .badge:nth-child(2) { 	transition-delay: 0.9s; } .slide.active .badge:nth-child(3) { 	transition-delay: 0.95s; } .badge-icon { 	width: 8px; 	height: 8px; 	background: #9fff6b; 	border-radius: 50%; } .add-button { 	position: absolute; 	bottom: 30px; 	right: 30px; 	width: 32px; 	height: 32px; 	background: transparent; 	border: 2px solid #9fff6b; 	border-radius: 50%; 	display: flex; 	align-items: center; 	justify-content: center; 	cursor: pointer; 	transition: all 0.4s ease; 	z-index: 3; } .add-button::before, .add-button::after { 	content: ""; 	position: absolute; 	background: #9fff6b; 	transition: all 0.4s ease; } .add-button::before { 	width: 12px; 	height: 2px; } .add-button::after { 	width: 2px; 	height: 12px; 	transform: rotate(0deg); } .slide.active .add-button::before { 	transform: rotate(0deg); } .slide.active .add-button::after { 	opacity: 0; 	transform: scale(0); } .navigation-arrows { 	position: absolute; 	top: 50%; 	transform: translateY(-50%); 	width: 50px; 	height: 50px; 	background: rgba(255, 255, 255, 0.1); 	border: none; 	border-radius: 50%; 	color: white; 	cursor: pointer; 	font-size: 20px; 	display: flex; 	align-items: center; 	justify-content: center; 	transition: all 0.3s ease; 	z-index: 4; 	backdrop-filter: blur(10px); } .nav-prev { 	left: 20px; } .nav-next { 	right: 20px; } .navigation-arrows:hover { 	background: rgba(255, 255, 255, 0.2); } @media (max-width: 768px) { 	.accordion-slider { 		flex-direction: column; 	} 	.slide { 		flex: 1; 		min-height: 80px; 	} 	.slide.active { 		flex: 2; 	} 	.slide-number { 		font-size: 32px; 	} 	.car-brand { 		transform: none; 		position: static; 	} }
script.js: class AccordionSlider { 	constructor() { 		this.slides = document.querySelectorAll(".slide"); 		this.prevBtn = document.querySelector(".nav-prev"); 		this.nextBtn = document.querySelector(".nav-next"); 		this.currentIndex = -1; 		this.init(); 	} 	init() { 		this.slides.forEach((slide, index) => { 			slide.addEventListener("click", () => this.setActiveSlide(index)); 		}); 		this.prevBtn.addEventListener("click", () => this.previousSlide()); 		this.nextBtn.addEventListener("click", () => this.nextSlide()); 		document.addEventListener("keydown", (e) => { 			if (e.key === "ArrowLeft") this.previousSlide(); 			if (e.key === "ArrowRight") this.nextSlide(); 		}); 	} 	setActiveSlide(index) { 		if (this.currentIndex === index) { 			this.slides.forEach((slide) => slide.classList.remove("active")); 			this.currentIndex = -1; 		} else { 			this.slides.forEach((slide) => slide.classList.remove("active")); 			this.slides[index].classList.add("active"); 			this.currentIndex = index; 		} 	} 	nextSlide() { 		const nextIndex = 			this.currentIndex === -1 ? 0 : (this.currentIndex + 1) % this.slides.length; 		this.setActiveSlide(nextIndex); 	} 	previousSlide() { 		const prevIndex = 			this.currentIndex === -1 				? this.slides.length - 1 				: (this.currentIndex - 1 + this.slides.length) % this.slides.length; 		this.setActiveSlide(prevIndex); 	} } document.addEventListener("DOMContentLoaded", () => { 	new AccordionSlider(); });
